import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { contentApi } from '../../services/api';
import { useNotify } from '../../hooks/useNotify';
import '../Admin.css';

const INITIAL = {
  title: '',
  description: '',
  thumbnail: '',
  videoUrl: '',
  duration: '',
  featured: false,
  trending: false,
};

export default function UploadVideo() {
  const [form, setForm] = useState(INITIAL);
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();
  const notify = useNotify();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await contentApi.create({
        type: 'video',
        title: form.title,
        description: form.description,
        thumbnail: form.thumbnail,
        videoUrl: form.videoUrl,
        duration: form.duration ? parseInt(form.duration, 10) : undefined,
        featured: form.featured,
        trending: form.trending,
      });
      notify.success('Video published successfully');
      navigate('/admin/videos');
    } catch (err) {
      notify.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="dash-page">
      <div className="dash-page__header">
        <div>
          <Link to="/admin/videos" className="dash-breadcrumb">← Back to Videos</Link>
          <h1>Upload Video</h1>
          <p>Add a new video to the Very Direct platform</p>
        </div>
      </div>

      <form className="upload-form" onSubmit={handleSubmit}>
        {error && <div className="form-error">{error}</div>}

        <div className="upload-form__grid">
          <div className="upload-form__main">
            <div className="upload-form__section">
              <h2>Video Details</h2>
              <label>
                Title <span className="required">*</span>
                <input
                  value={form.title}
                  onChange={(e) => setForm({ ...form, title: e.target.value })}
                  placeholder="Enter video title"
                  required
                />
              </label>
              <label>
                Description
                <textarea
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  placeholder="Short description for the video"
                  rows={4}
                />
              </label>
              <label>
                Video URL <span className="required">*</span>
                <input
                  value={form.videoUrl}
                  onChange={(e) => setForm({ ...form, videoUrl: e.target.value })}
                  placeholder="https://example.com/video.mp4"
                  required
                />
              </label>
            </div>
          </div>

          <div className="upload-form__side">
            <div className="upload-form__section">
              <h2>Thumbnail</h2>
              <label>
                Thumbnail URL
                <input
                  value={form.thumbnail}
                  onChange={(e) => setForm({ ...form, thumbnail: e.target.value })}
                  placeholder="https://example.com/thumb.jpg"
                />
              </label>
              {form.thumbnail && (
                <img src={form.thumbnail} alt="Preview" className="upload-form__preview" />
              )}
            </div>

            <div className="upload-form__section">
              <h2>Settings</h2>
              <label>
                Duration (seconds)
                <input
                  type="number"
                  min="0"
                  value={form.duration}
                  onChange={(e) => setForm({ ...form, duration: e.target.value })}
                  placeholder="e.g. 120"
                />
              </label>
              <label className="upload-checkbox">
                <input
                  type="checkbox"
                  checked={form.featured}
                  onChange={(e) => setForm({ ...form, featured: e.target.checked })}
                />
                Mark as Featured
              </label>
              <label className="upload-checkbox">
                <input
                  type="checkbox"
                  checked={form.trending}
                  onChange={(e) => setForm({ ...form, trending: e.target.checked })}
                />
                Mark as Trending
              </label>
            </div>

            <button type="submit" className="btn btn-primary upload-form__submit" disabled={saving}>
              {saving ? 'Publishing...' : 'Publish Video'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}
